import{_ as s,C as i,o as a,c as r,a0 as n,b as d,w as o,a as l,E as c,a1 as p}from"./chunks/framework.BjpW4enL.js";const k=JSON.parse('{"title":"Roadmap de Engenharia","description":"Plano iterado para o Grafo T4 e Federação","frontmatter":{"title":"Roadmap de Engenharia","description":"Plano iterado para o Grafo T4 e Federação"},"headers":[],"relativePath":"10_Fundacao/ROADMAP.md","filePath":"10_Fundacao/ROADMAP.md","lastUpdated":1782592277000}'),m={name:"10_Fundacao/ROADMAP.md"};function u(h,e,g,x,f,E){const t=i("Mermaid");return a(),r("div",null,[e[1]||(e[1]=n('<h1 id="plano-iterado-matriz-de-eixos-e-checkpoints" tabindex="-1">Plano Iterado: Matriz de Eixos e Checkpoints <a class="header-anchor" href="#plano-iterado-matriz-de-eixos-e-checkpoints" aria-label="Permalink to &quot;Plano Iterado: Matriz de Eixos e Checkpoints&quot;">​</a></h1><p>O plano arquitetural foi refatorado. Os <strong>Eixos</strong> representam subtarefas e responsabilidades exclusivas no desenvolvimento. Os <strong>Nós de Interseção</strong> representam os <strong>Checkpoints</strong> entregáveis onde as subtarefas se encontram para formar uma capacidade real do sistema.</p><p>Nosso foco imediato é <strong>corrigir o pipeline atual até obtermos um Grafo T4 Local Validado</strong> antes de injetar a complexidade do nó remoto (Supabase).</p><h2 id="eixos-subtarefas-exclusivas" tabindex="-1">Eixos (Subtarefas Exclusivas) <a class="header-anchor" href="#eixos-subtarefas-exclusivas" aria-label="Permalink to &quot;Eixos (Subtarefas Exclusivas)&quot;">​</a></h2><ul><li><strong>Eixo X (Ingestion &amp; Pipeline):</strong> Estabilização do processo local de leitura do disco, chunking, e vetorização (Qdrant).</li><li><strong>Eixo Y (Grafo T4 &amp; Semântica):</strong> Criação, validação e resolução temporal de arestas lógicas (<code>depends_on</code>, <code>semantic_bridge</code>).</li><li><strong>Eixo Z (Storage &amp; Fila):</strong> Desacoplamento da camada de persistência (StorageAdapter) e transição da fila em RAM para disco.</li></ul><h2 id="mapa-de-intersecoes-checkpoints" tabindex="-1">Mapa de Interseções (Checkpoints) <a class="header-anchor" href="#mapa-de-intersecoes-checkpoints" aria-label="Permalink to &quot;Mapa de Interseções (Checkpoints)&quot;">​</a></h2><p>Os cruzamentos entre os eixos formam os checkpoints críticos de validação:</p><h3 id="checkpoint-1-ingestao-estavel-eixo-x-∩-eixo-z" tabindex="-1">Checkpoint 1: Ingestão Estável <code>(Eixo X ∩ Eixo Z)</code> <a class="header-anchor" href="#checkpoint-1-ingestao-estavel-eixo-x-∩-eixo-z" aria-label="Permalink to &quot;Checkpoint 1: Ingestão Estável `(Eixo X ∩ Eixo Z)`&quot;">​</a></h3><ul><li><strong>Objetivo:</strong> O pipeline atual lê os arquivos e usa o <code>StorageAdapter</code> local de forma limpa, sem estourar o limite da fila <code>mpsc</code>.</li><li><strong>Status:</strong> Planejado.</li></ul><h3 id="checkpoint-2-t4-local-validado-eixo-x-∩-eixo-y" tabindex="-1">Checkpoint 2: T4 Local Validado <code>(Eixo X ∩ Eixo Y)</code> <a class="header-anchor" href="#checkpoint-2-t4-local-validado-eixo-x-∩-eixo-y" aria-label="Permalink to &quot;Checkpoint 2: T4 Local Validado `(Eixo X ∩ Eixo Y)`&quot;">​</a></h3><ul><li><strong>Objetivo:</strong> Os chunks ingeridos corretamente geram arestas <code>depends_on</code> precisas usando as ASTs e formam um grafo topológico coeso no Qdrant/Postgres local, sem falsos positivos.</li><li><strong>Status:</strong> Foco Atual.</li></ul><h3 id="checkpoint-3-desacoplamento-stateful-eixo-y-∩-eixo-z" tabindex="-1">Checkpoint 3: Desacoplamento Stateful <code>(Eixo Y ∩ Eixo Z)</code> <a class="header-anchor" href="#checkpoint-3-desacoplamento-stateful-eixo-y-∩-eixo-z" aria-label="Permalink to &quot;Checkpoint 3: Desacoplamento Stateful `(Eixo Y ∩ Eixo Z)`&quot;">​</a></h3><ul><li><strong>Objetivo:</strong> A geração de arestas semânticas passa a responder a uma fila persistente (Postgres local) em vez de eventos efêmeros na RAM, garantindo que o T4 sobreviva a reboots sob stress.</li><li><strong>Status:</strong> Planejado.</li></ul><h3 id="checkpoint-4-prontidao-para-federacao-x-∩-y-∩-z" tabindex="-1">Checkpoint 4: Prontidão para Federação <code>(X ∩ Y ∩ Z)</code> <a class="header-anchor" href="#checkpoint-4-prontidao-para-federacao-x-∩-y-∩-z" aria-label="Permalink to &quot;Checkpoint 4: Prontidão para Federação `(X ∩ Y ∩ Z)`&quot;">​</a></h3><ul><li><strong>Objetivo:</strong> O motor local está perfeitamente estável, as filas são persistentes e o storage abstraído. O NEXUS está pronto para receber o <code>RemoteStorageAdapter</code> (Supabase) sem alterar a lógica de negócios do Grafo T4.</li><li><strong>Status:</strong> Destino Final.</li></ul><h2 id="diagrama-de-intersecao" tabindex="-1">Diagrama de Interseção <a class="header-anchor" href="#diagrama-de-intersecao" aria-label="Permalink to &quot;Diagrama de Interseção&quot;">​</a></h2>',16)),(a(),d(p,null,{default:o(()=>[c(t,{id:"mermaid-98",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20X%5BEixo%20X%3A%20Ingestion%5D%20--%3E%20C1((CP%201%3A%20Ingest%C3%A3o%20Est%C3%A1vel))%0A%20%20%20%20Z%5BEixo%20Z%3A%20Storage%2FFila%5D%20--%3E%20C1%0A%20%20%20%20%0A%20%20%20%20X%20--%3E%20C2((CP%202%3A%20T4%20Local%20Validado))%0A%20%20%20%20Y%5BEixo%20Y%3A%20Grafo%20T4%5D%20--%3E%20C2%0A%20%20%20%20%0A%20%20%20%20Y%20--%3E%20C3((CP%203%3A%20Desacoplamento))%0A%20%20%20%20Z%20--%3E%20C3%0A%20%20%20%20%0A%20%20%20%20C1%20--%3E%20C4%7BCP%204%3A%20Prontid%C3%A3o%20Remota%7D%0A%20%20%20%20C2%20--%3E%20C4%0A%20%20%20%20C3%20--%3E%20C4%0A"})]),fallback:o(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1}))])}const b=s(m,[["render",u]]);export{k as __pageData,b as default};
